
import { defineComponent, ref, provide } from "vue";
import { roleList, delRole } from "@/server/http/api/system";
import Updaterole from "./role/modal/Updaterole.vue";
import AddRole from "./role/modal/AddRole.vue";
import UpdateJurisdiction from "./role/modal/UpdateJurisdiction.vue";
import { getAllMenu } from "@/server/http/api/system";
import { toTreeMenu } from "@/utils/toTree";
const columns = [
  {
    title: "角色名称",
    dataIndex: "roleName",
    key: "roleName",
    slots: { customRender: "roleName" },
  },
  {
    title: "备注",
    dataIndex: "roleRemark",
    key: "roleRemark",
  },

  {
    title: "操作",
    key: "action",
    slots: { customRender: "action" },
  },
];
export default defineComponent({
  components: { Updaterole, AddRole, UpdateJurisdiction },
  setup() {
    // 搜索
    const rolelist = ref([]);
    const value = ref<string>("");
    function init(value: any) {
      roleList({ roleName: value }).then((res: any) => {
        if (res.data.code === 200) {
          rolelist.value = res.data.data;
        }
      });
    }
    roleList({}).then((res: any) => {
      if (res.data.code === 200) {
        rolelist.value = res.data.data;
      }
    });
    const onSearch = (searchValue: string) => {
      init(searchValue);
    };
    let timer: any;
    const onChange = () => {
      clearTimeout(timer);
      timer = setTimeout(() => {
        init(value.value);
      }, 600);
    };

    function del(id: number) {
      delRole(id).then((res: any) => {
        if (res.data.code === 200) {
          init(value.value);
        }
      });
    }
    // 查询权限
    let treeData = ref([]);

    getAllMenu().then((res: any) => {
      //console.log(res);
      
      if (res.data.code === 200) {
        treeData.value = toTreeMenu(res.data.data);
        //console.log(treeData.value);
        
      }
    });

    provide("rolelist", init);
    return {
      onChange,
      onSearch,
      value,
      rolelist,
      columns,
      del,
      init,
      treeData,
    };
  },
});
