
import { ref, defineComponent, reactive, inject, toRaw } from "vue";

import { addRole } from "@/server/http/api/system";

export default defineComponent({
  components: {
  
  },
  setup(props) {
    const formRef = ref();

    const rules = {
      roleName: [
        { required: true, message: "角色名称不能为空", trigger: "blur" },
        { min: 1, max: 64, message: "名称在64个字符之内", trigger: "blur" },
      ],
    };
    const init: any = inject("rolelist");
    const formState: any = reactive({
      roleName: "",
      roleRemark: "",
    });

    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);
    const showModal = () => {
      visible.value = true;
    };

    const handleOk = () => {
      formRef.value
        .validate()
        .then(() => {
          confirmLoading.value = true;
          addRole(formState).then((res: any) => {
            if (res.data.code === 200) {
              init();
            }
            formState.roleName = "";
            formState.roleRemark = "";
            visible.value = false;
            confirmLoading.value = false;
          });
        })
        .catch((error: any) => {
          //console.log("error", error);
        });
    };

    return {
      formState,
      visible,
      confirmLoading,
      showModal,
      handleOk,
      labelCol: { span: 4 },
      wrapperCol: { span: 20 },
      rules,
      formRef,
    };
  },
});
