
import { ref, defineComponent, reactive, inject, watch } from "vue";

import { getRoleMenu, grant } from "@/server/http/api/system";
export default defineComponent({
  props: ["detail", "treeData"],
  components: {},
  setup(props) {
    const checkedKeys: any = ref([]);
    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);

    const showModal = (roleId: number) => {
      getRoleMenu(roleId).then((res: any) => {
        //console.log(res);
        if (res.data.code === 200) {
          checkedKeys.value = res.data.data;
        }
      });
      visible.value = true;
    };

    // let arr: any = [];
    const handleOk = () => {
      confirmLoading.value = true;
      // checkedKeys.value.map((item: any) => {
      //   arr.push({ functionId: item });
      // });
      grant({
        roleId: props.detail.roleId,
        list: checkedKeys.value,
      }).then((res: any) => {
        confirmLoading.value = false;
        visible.value = false;
      });
    };
    return {
      checkedKeys,
      visible,
      confirmLoading,
      showModal,
      handleOk,
      labelCol: { span: 4 },
      wrapperCol: { span: 20 },
    };
  },
});
