
import { ref, defineComponent, reactive, inject } from "vue";

import { editRole } from "@/server/http/api/system";
export default defineComponent({
  props: ["detail"],
  components: {

  },
  setup(props) {
    const formRef = ref();

    const rules = {
      roleName: [
        { required: true, message: "角色名称不能为空", trigger: "blur" },
        { min: 1, max: 64, message: "名称在64个字符之内", trigger: "blur" },
      ],
    };

    const init: any = inject("rolelist");
    const formState: any = reactive({
      roleId: "",
      roleName: "",
      roleRemark: "",
    });

    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);
    const showModal = (roleId: number) => {
      formState.roleId = roleId;
      formState.roleName = props.detail.roleName;
      formState.roleRemark = props.detail.roleRemark;

      visible.value = true;
    };
    const handleOk = () => {
      formRef.value
        .validate()
        .then(() => {
          confirmLoading.value = true;
          editRole(formState).then((res: any) => {
            if (res.data.code === 200) {
              init();
            }
            visible.value = false;
            confirmLoading.value = false;
          });
        })
        .catch((error: any) => {
          //console.log("error", error);
        });
    };
    return {
      rules,
      formRef,
      formState,
      visible,
      confirmLoading,
      showModal,
      handleOk,
      labelCol: { span: 4 },
      wrapperCol: { span: 20 },
    };
  },
});
